#nullable enable // autogenerated

using System;
using PVZEngine;
using TMPro;
using UnityEngine;

namespace MVZ2.UI
{
    public class MoreOptionsCategory : MonoBehaviour, IOptionsDialogElement
    {
        public void UpdateOptions(MoreOptionsCategoryViewData viewData)
        {
            label.text = viewData.label;
            list.updateList(viewData.widgets.Length, (i, obj) =>
            {
                var data = viewData.widgets[i];
                var widgets = obj.GetComponent<OptionWidgets>();
                widgets.UpdateWidgets(data);

                var tooltipHander = obj.GetComponent<TooltipHandler>();
                tooltipHander.text = data.tooltipText;
                tooltipHander.context = data.tooltipContext;
            },
            obj =>
            {
                var widgets = obj.GetComponent<OptionWidgets>();
                widgets.OnToggleValueChanged += OnToggleValueChangedCallback;
                widgets.OnSliderValueChanged += OnSliderValueChangedCallback;
                widgets.OnSliderEnd += OnSliderEndCallback;
                widgets.OnDropdownValueChanged += OnDropdownValueChangedCallback;
                widgets.OnButtonClicked += OnButtonClickedCallback;

                var tooltipHander = obj.GetComponent<TooltipHandler>();
                tooltipHander.OnPointerEnter += OnTooltipShowCallback;
                tooltipHander.OnPointerExit += OnTooltipHideCallback;
            },
            obj =>
            {
                var widgets = obj.GetComponent<OptionWidgets>();
                widgets.OnToggleValueChanged -= OnToggleValueChangedCallback;
                widgets.OnSliderValueChanged -= OnSliderValueChangedCallback;
                widgets.OnSliderEnd -= OnSliderEndCallback;
                widgets.OnDropdownValueChanged -= OnDropdownValueChangedCallback;
                widgets.OnButtonClicked -= OnButtonClickedCallback;

                var tooltipHander = obj.GetComponent<TooltipHandler>();
                tooltipHander.OnPointerEnter -= OnTooltipShowCallback;
                tooltipHander.OnPointerExit -= OnTooltipHideCallback;
            });
        }
        public OptionWidgets? GetWidgetsByID(NamespaceID id)
        {
            foreach (var widgets in list.getElements<OptionWidgets>())
            {
                if (widgets.Exists() && widgets.GetOptionID() == id)
                    return widgets;
            }
            return null;
        }
        private void OnToggleValueChangedCallback(OptionWidgets widgets, bool value)
        {
            OnToggleValueChanged?.Invoke(widgets, value);
        }
        private void OnSliderValueChangedCallback(OptionWidgets widgets, float value)
        {
            OnSliderValueChanged?.Invoke(widgets, value);
        }
        private void OnSliderEndCallback(OptionWidgets widgets, float value)
        {
            OnSliderEnd?.Invoke(widgets, value);
        }
        private void OnDropdownValueChangedCallback(OptionWidgets widgets, int value)
        {
            OnDropdownValueChanged?.Invoke(widgets, value);
        }
        private void OnButtonClickedCallback(OptionWidgets widgets)
        {
            OnButtonClicked?.Invoke(widgets);
        }
        private void OnTooltipShowCallback(TooltipHandler handler)
        {
            OnTooltipShow?.Invoke(handler);
        }
        private void OnTooltipHideCallback(TooltipHandler handler)
        {
            OnTooltipHide?.Invoke(handler);
        }

        public event Action<OptionWidgets, bool>? OnToggleValueChanged;
        public event Action<OptionWidgets, float>? OnSliderValueChanged;
        public event Action<OptionWidgets, float>? OnSliderEnd;
        public event Action<OptionWidgets, int>? OnDropdownValueChanged;
        public event Action<OptionWidgets>? OnButtonClicked;
        public event Action<TooltipHandler>? OnTooltipShow;
        public event Action<TooltipHandler>? OnTooltipHide;

        [SerializeField]
        private TextMeshProUGUI label;
        [SerializeField]
        private ElementList list;
    }
    public struct MoreOptionsCategoryViewData
    {
        public string label;
        public OptionWidgetsViewData[] widgets;
    }
}
